-- ============================================================================
-- Quiz Seed: Leviticus — Part 3 (Chapters 21–27)
-- 3 difficulties × 7 chapters = 112 total questions
--   kids:   3 per chapter  = 21
--   teens:  5 per chapter  = 35
--   adults: 8 per chapter  = 56
-- ============================================================================

-- ═══ Leviticus Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 21, 'kids', 1, 'Who were the special rules in Leviticus 21 written for?', 'The priests', 'All the people of Israel', 'The kings', 'The elders', 'a', 'Leviticus 21:1 — "And the LORD said unto Moses, Speak unto the priests the sons of Aaron."'),
('Leviticus', 21, 'kids', 2, 'Who was the most important priest that had extra holiness rules?', 'The high priest', 'The youngest priest', 'The eldest son', 'The scribe', 'a', 'Leviticus 21:10 — "And he that is the high priest among his brethren, upon whose head the anointing oil was poured."'),
('Leviticus', 21, 'kids', 3, 'Could a priest with a physical blemish offer the burnt offerings at the altar?', 'No, he could not offer them', 'Yes, he could offer any offering', 'Only on the Sabbath', 'Only with the help of another priest', 'a', 'Leviticus 21:17 — "Whosoever he be of thy seed in their generations that hath any blemish, let him not approach to offer the bread of his God."'),
-- Teens
('Leviticus', 21, 'teens', 1, 'For whose dead body could a priest defile himself without breaking the law?', 'Only his mother or father', 'His kin that is near unto him: mother, father, son, daughter, brother, and virgin sister', 'No one — priests could never defile themselves', 'Any Israelite from his tribe', 'a', 'Leviticus 21:2-3 — "But for his kin, that is near unto him, that is, for his mother, and for his father, and for his son, and for his daughter, and for his brother."'),
('Leviticus', 21, 'teens', 2, 'What restriction was placed on who a priest could marry?', 'He could marry any Israelite woman', 'He could not marry a widow, a divorced woman, a profane woman, or a harlot — only a virgin of his own people', 'He could only marry a widow', 'He had to marry a woman from the tribe of Levi', 'a', 'Leviticus 21:7 — "They shall not take a wife that is a whore, or profane; neither shall they take a woman put away from her husband."'),
('Leviticus', 21, 'teens', 3, 'What happened if a priest''s daughter played the whore?', 'She was cast out of the camp', 'She was to be burnt with fire', 'She was fined and rebuked', 'She was given to another family', 'a', 'Leviticus 21:9 — "And the daughter of any priest, if she profane herself by playing the whore, she profaneth her father: she shall be burnt with fire."'),
('Leviticus', 21, 'teens', 4, 'What additional mourning restriction was placed on the high priest?', 'He could not mourn at all — not even for his parents', 'He could mourn privately but not publicly', 'He was allowed to mourn for seven days', 'He could only mourn on the Day of Atonement', 'a', 'Leviticus 21:11 — "Neither shall he go in to any dead body, nor defile himself for his father, or for his mother."'),
('Leviticus', 21, 'teens', 5, 'Could a priest with a blemish still eat of the holy food?', 'Yes, he could eat the bread of his God', 'No, blemished priests were completely excluded', 'Only on certain feast days', 'Only if approved by the high priest', 'a', 'Leviticus 21:22 — "He shall eat the bread of his God, both of the most holy, and of the holy."'),
-- Adults
('Leviticus', 21, 'adults', 1, 'What is the theological reason priests were required to maintain exceptional holiness?', 'They were of a higher social class', 'They offered the bread of God and were His consecrated servants — their purity represented His holiness to Israel', 'They were simply following a priestly tradition', 'God wanted to distinguish them from Levites visually', 'a', 'Leviticus 21:6 — "They shall be holy unto their God, and not profane the name of their God: for the offerings of the LORD made by fire...they do offer."'),
('Leviticus', 21, 'adults', 2, 'What does the phrase "profane the name of their God" in Leviticus 21:6 reveal about the stakes of priestly conduct?', 'It means the priest would lose his salary', 'A priest''s sinful behavior brought dishonor to God''s own holy name before the congregation', 'It was a legal term for contract violation', 'It referred only to verbal blasphemy', 'a', 'Leviticus 21:6 — "They shall be holy unto their God, and not profane the name of their God." Priestly conduct was a public testimony to God''s character.'),
('Leviticus', 21, 'adults', 3, 'What specific reason does Leviticus 21:12 give for why the high priest must not leave the sanctuary?', 'He must guard the holy objects', 'He must not profane the sanctuary because the consecration of God''s anointing oil is upon him', 'He was too valuable to risk outside', 'He needed to intercede continually', 'a', 'Leviticus 21:12 — "Neither shall he go out of the sanctuary, nor profane the sanctuary of his God; for the crown of the anointing oil of his God is upon him."'),
('Leviticus', 21, 'adults', 4, 'How many physical blemishes are listed in Leviticus 21:18-20 that disqualified a priest from approaching the altar?', 'Five', 'Seven', 'Twelve', 'Nine', 'c', 'Leviticus 21:18-20 lists twelve blemishes including blindness, lameness, flat nose, broken foot, crooked back, scurvy, crookbacked, dwarf, blemish in eye, wen, scurvy, and broken hand.'),
('Leviticus', 21, 'adults', 5, 'What typological significance does the requirement of priestly physical perfection have in light of the New Testament?', 'It showed God valued physical appearance above character', 'It foreshadowed Christ the perfect High Priest who had no blemish — holy, harmless, undefiled, separate from sinners', 'It was a cultural health code with no spiritual meaning', 'It only applied in the wilderness period', 'a', 'Leviticus 21:17 prefigures Hebrews 7:26 — "For such an high priest became us, who is holy, harmless, undefiled, separate from sinners."'),
('Leviticus', 21, 'adults', 6, 'The restriction that the high priest could only marry a virgin (Leviticus 21:13) carries what deeper covenantal significance?', 'It was a practical policy to avoid inheritance disputes', 'The high priest as a type of Christ could only be "wedded" to a pure bride — typifying Christ and the Church as a holy, undefiled bride', 'It applied to all Israelite men in leadership', 'It was later rescinded under the monarchy', 'a', 'Leviticus 21:13-14 — "And he shall take a wife in her virginity." This typifies Ephesians 5:27, Christ presenting the church holy and without blemish.'),
('Leviticus', 21, 'adults', 7, 'What does Leviticus 21:8 instruct the congregation regarding the priest?', 'To obey him as if he were a king', 'To sanctify him — thou shalt sanctify him — because he offers the bread of God', 'To support him financially', 'To test him before ordination', 'a', 'Leviticus 21:8 — "Thou shalt sanctify him therefore; for he offereth the bread of thy God: he shall be holy unto thee: for I the LORD, which sanctify you, am holy."'),
('Leviticus', 21, 'adults', 8, 'What does the statement "I the LORD do sanctify them" (Leviticus 21:15) reveal about the source of priestly holiness?', 'Holiness comes from ritual observance alone', 'Holiness is ultimately God''s gift and work — the priest''s sanctification is rooted in divine action, not merely human compliance', 'It shows the high priest earned his status', 'It was a ceremonial affirmation with no deeper meaning', 'a', 'Leviticus 21:15 — "Neither shall he profane his seed among his people: for I the LORD do sanctify him." God is the author and sustainer of true holiness.');

-- ═══ Leviticus Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 22, 'kids', 1, 'Could a sick priest eat from the holy offerings?', 'No, he had to be clean first', 'Yes, always', 'Only on Sabbath', 'Only with water', 'a', 'Leviticus 22:4 — "What man soever of the seed of Aaron is a leper, or hath a running issue; he shall not eat of the holy things, until he be clean."'),
('Leviticus', 22, 'kids', 2, 'What kind of animals were allowed to be offered to God?', 'Animals without blemish', 'Any animal the priest chose', 'Only wild animals', 'Only sheep', 'a', 'Leviticus 22:21 — "Whosoever offereth a sacrifice of peace offerings unto the LORD to accomplish his vow, or a freewill offering in beeves or sheep, it shall be perfect to be accepted; there shall be no blemish therein."'),
('Leviticus', 22, 'kids', 3, 'Could a stranger who was not from a priestly family eat the holy food?', 'No, strangers could not eat it', 'Yes, if the priest invited them', 'Only Levites could', 'Only on feasts', 'a', 'Leviticus 22:10 — "There shall no stranger eat of the holy thing: a sojourner of the priest, or an hired servant, shall not eat of the holy thing."'),
-- Teens
('Leviticus', 22, 'teens', 1, 'Who among the priest''s household could lawfully eat of the holy offerings?', 'A bought servant born in his house, and his daughter if she had no husband', 'Any Israelite who was a friend of the priest', 'All Levites regardless of household', 'Only the priest himself', 'a', 'Leviticus 22:11-12 — "But if the priest buy any soul with his money...he shall eat of it...But the priest''s daughter, if she be married unto a stranger, she may not eat of an offering of the holy things."'),
('Leviticus', 22, 'teens', 2, 'If a person accidentally ate a holy thing, what were they required to do?', 'Fast for seven days', 'Restore the holy thing and add a fifth part to it', 'Bring a sin offering only', 'Be excluded from the congregation', 'a', 'Leviticus 22:14 — "And if a man eat of the holy thing unwittingly, then he shall put the fifth part thereof unto it, and shall give it unto the priest with the holy thing."'),
('Leviticus', 22, 'teens', 3, 'Could a newborn calf or lamb be offered before it was eight days old?', 'No, it had to be at least eight days old', 'Yes, any age was acceptable', 'It had to be at least one month old', 'It depended on the type of offering', 'a', 'Leviticus 22:27 — "When a bullock, or a sheep, or a goat, is brought forth, then it shall be seven days under the dam; and from the eighth day and thenceforth it shall be accepted for an offering."'),
('Leviticus', 22, 'teens', 4, 'Was it lawful to offer a mother animal and her young on the same day?', 'No, they could not be slaughtered on the same day', 'Yes, it was encouraged as a double offering', 'Only if it was a freewill offering', 'Only on the Day of Atonement', 'a', 'Leviticus 22:28 — "Whether it be a cow or ewe, ye shall not kill it and her young both in one day."'),
('Leviticus', 22, 'teens', 5, 'What defects made an animal unacceptable as an offering to God?', 'Blindness, broken bones, maimed, having a wen, scurvy, or scab', 'Old age or small size', 'Wrong color or incorrect breed', 'Being from a foreign flock', 'a', 'Leviticus 22:22 — "Blind, or broken, or maimed, or having a wen, or scurvy, or scabbed, ye shall not offer these unto the LORD."'),
-- Adults
('Leviticus', 22, 'adults', 1, 'What does the repeated phrase "I am the LORD" throughout Leviticus 22 underscore about the holiness laws?', 'It is a legal formula with no deeper meaning', 'It anchors all holiness regulations in the authority and character of God Himself — obedience is a response to who He is', 'It identifies the source of the Levitical text', 'It is a doxological formula borrowed from Egypt', 'a', 'Leviticus 22:31-32 — "Therefore shall ye keep my commandments, and do them: I am the LORD...I am the LORD which hallow you."'),
('Leviticus', 22, 'adults', 2, 'What does the requirement for unblemished offerings typologically point to in the New Testament?', 'It shows God values physical perfection in worshippers', 'It prefigures Christ as the Lamb without blemish and without spot offered for our sins', 'It was only a sanitary measure', 'It applied only under Mosaic law with no lasting significance', 'a', 'Leviticus 22:21 points to 1 Peter 1:19 — "But with the precious blood of Christ, as of a lamb without blemish and without spot."'),
('Leviticus', 22, 'adults', 3, 'What specific uncleanness conditions are listed in Leviticus 22:4-6 that prevented a priest from eating holy things?', 'Leprosy, running issue, contact with a dead body, an emission, touching a creeping thing, or touching a man that is unclean', 'Only leprosy and skin disease', 'Contact with Gentiles alone', 'Only touching the dead', 'a', 'Leviticus 22:4-6 — "What man soever...is a leper, or hath a running issue...or a man whose seed goeth from him...whosoever toucheth any such shall be unclean."'),
('Leviticus', 22, 'adults', 4, 'What does Leviticus 22:9 warn the priests will happen if they profane the holy things?', 'They will lose their priestly inheritance', 'They shall bear sin for it and die', 'They will be exiled from the camp', 'They will be fined by the congregation', 'a', 'Leviticus 22:9 — "They shall therefore keep mine ordinance, lest they bear sin for it, and die therefore, if they profane it."'),
('Leviticus', 22, 'adults', 5, 'Why was the offering of a freewill offering held to a higher standard — being perfect — while a vow-based offering allowed minor imperfections for certain animals?', 'The Law was inconsistent in this area', 'Freewill offerings were a pure act of devotion and required perfection; vow offerings for cattle allowed for slight redundant overgrowth but no serious blemish', 'The high priest could waive standards for vow offerings', 'Freewill offerings were cheaper', 'a', 'Leviticus 22:23 — "Either a bullock or a lamb that hath any thing superfluous or lacking in his parts, that mayest thou offer for a freewill offering; but for a vow it shall not be accepted."'),
('Leviticus', 22, 'adults', 6, 'What does Leviticus 22:32 identify as the goal of God''s holiness laws among Israel?', 'Political order and social cohesion', 'That God''s holy name not be profaned — "I will be hallowed among the children of Israel"', 'Economic fairness in offerings', 'Priestly income regulation', 'a', 'Leviticus 22:32 — "Neither shall ye profane my holy name; but I will be hallowed among the children of Israel: I am the LORD which hallow you."'),
('Leviticus', 22, 'adults', 7, 'What redemption principle does the priest''s daughter illustrate in Leviticus 22:12-13?', 'Women had no legal standing in priestly households', 'Belonging to the priestly household determines access to holy provision — she loses access upon marrying out but regains it upon returning', 'All daughters of priests permanently lost access upon marriage', 'She could petition the elders for reinstatement', 'a', 'Leviticus 22:12-13 — If married to a stranger she may not eat; but if widowed or divorced and returned to her father''s house she shall eat of her father''s meat.'),
('Leviticus', 22, 'adults', 8, 'What is the significance of God saying "I brought you out of Egypt" at the end of Leviticus 22:33 in the context of holiness commands?', 'It is a historical footnote', 'The exodus is the foundational act of redemption that obligates Israel to worship a holy God — holiness flows from grace, not the reverse', 'It refers only to the priests'' ancestral history', 'It was added by a later editor', 'a', 'Leviticus 22:33 — "That brought you out of the land of Egypt, to be your God: I am the LORD." The Redeemer''s identity grounds the call to holy offerings.');

-- ═══ Leviticus Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 23, 'kids', 1, 'What special day did God say was a day of rest every week?', 'The Sabbath', 'The new moon', 'Passover', 'The feast of trumpets', 'a', 'Leviticus 23:3 — "Six days shall work be done: but the seventh day is the sabbath of rest, an holy convocation."'),
('Leviticus', 23, 'kids', 2, 'What feast reminded Israel of the time God brought them out of Egypt?', 'Passover', 'Tabernacles', 'Pentecost', 'Trumpets', 'a', 'Leviticus 23:5 — "In the fourteenth day of the first month at even is the LORD''S passover."'),
('Leviticus', 23, 'kids', 3, 'During the Feast of Tabernacles, where did the Israelites live for seven days?', 'In booths made of branches', 'In tents by the river', 'In their own houses', 'In the tabernacle courtyard', 'a', 'Leviticus 23:42 — "Ye shall dwell in booths seven days; all that are Israelites born shall dwell in booths."'),
-- Teens
('Leviticus', 23, 'teens', 1, 'What were the seven appointed feasts of the LORD listed in Leviticus 23?', 'Sabbath, Passover, Unleavened Bread, Firstfruits, Pentecost, Trumpets, Day of Atonement, and Tabernacles', 'New Moon, Passover, Weeks, Trumpets, Atonement, Tabernacles, and Purim', 'Passover, Weeks, Booths, Sabbath, New Year, Atonement, and Dedication', 'Passover, Unleavened Bread, Firstfruits, Pentecost, Trumpets, Atonement, and Tabernacles', 'a', 'Leviticus 23 — The eight convocations include Sabbath (v.3), Passover (v.5), Unleavened Bread (v.6), Firstfruits (v.10), Pentecost/Weeks (v.16), Trumpets (v.24), Day of Atonement (v.27), and Tabernacles (v.34).'),
('Leviticus', 23, 'teens', 2, 'On what date did the Feast of Unleavened Bread begin, and how long did it last?', 'The 15th of the first month, for seven days', 'The 1st of the first month, for seven days', 'The 10th of the first month, for three days', 'The 14th of the first month, for ten days', 'a', 'Leviticus 23:6 — "And on the fifteenth day of the same month is the feast of unleavened bread unto the LORD: seven days ye must eat unleavened bread."'),
('Leviticus', 23, 'teens', 3, 'What was the Feast of Firstfruits and when was the sheaf waved before the LORD?', 'The first harvest was burned; waved on the first day of the third month', 'A sheaf of the firstfruits of harvest was waved before the LORD on the day after the Sabbath following Passover', 'The entire harvest was dedicated at the new moon', 'It was a private ceremony performed by the high priest on Passover', 'a', 'Leviticus 23:11 — "And he shall wave the sheaf before the LORD, to be accepted for you: on the morrow after the sabbath the priest shall wave it."'),
('Leviticus', 23, 'teens', 4, 'What special observance took place on the first day of the seventh month?', 'The Day of Atonement began', 'A memorial of blowing of trumpets, a holy convocation', 'The Jubilee was declared', 'The Feast of Tabernacles started', 'a', 'Leviticus 23:24 — "In the seventh month, in the first day of the month, shall ye have a sabbath, a memorial of blowing of trumpets, an holy convocation."'),
('Leviticus', 23, 'teens', 5, 'What was commanded during the Day of Atonement on the 10th of the seventh month?', 'A great feast and celebration', 'Afflicting their souls, offering a fire offering, and doing no work', 'Blowing trumpets all day long', 'Marching around the tabernacle', 'a', 'Leviticus 23:27 — "Also on the tenth day of this seventh month there shall be a day of atonement: it shall be an holy convocation unto you; and ye shall afflict your souls, and offer an offering made by fire unto the LORD."'),
-- Adults
('Leviticus', 23, 'adults', 1, 'What theological concept is conveyed by the term "holy convocations" used for all the appointed feasts in Leviticus 23?', 'Public holidays for rest only', 'Sacred assemblies called by God — the calendar itself is holy, and God''s people gather at His invitation to encounter Him', 'Optional observances left to individual conscience', 'Administrative meeting times for the priesthood', 'a', 'Leviticus 23:2 — "The feasts of the LORD, which ye shall proclaim to be holy convocations, even these are my feasts." God owns the feasts — they are His appointments.'),
('Leviticus', 23, 'adults', 2, 'How does the Feast of Firstfruits in Leviticus 23:10-11 typologically point to Christ''s resurrection?', 'It was only a harvest ceremony with no prophetic dimension', 'The firstfruits sheaf waved on the day after the Sabbath prefigures Christ as the firstfruits of them that slept, raised on the first day of the week', 'It predicted the day of Pentecost only', 'Firstfruits only applies to the nation of Israel''s future restoration', 'a', 'Leviticus 23:11 is fulfilled in 1 Corinthians 15:20 — "But now is Christ risen from the dead, and become the firstfruits of them that slept."'),
('Leviticus', 23, 'adults', 3, 'What is the theological connection between Pentecost (Feast of Weeks, Leviticus 23:16-17) and the events of Acts 2?', 'It is coincidental — the feast had no prophetic significance', 'The 50th day from Firstfruits when two wave loaves of leavened bread were offered typifies the outpouring of the Spirit on Jews and Gentiles at the birth of the Church', 'Pentecost only commemorated the giving of the Law at Sinai', 'The leavened loaves pointed to the corruption of the early Church', 'a', 'Leviticus 23:17 — "two wave loaves...they shall be baken with leaven" — leaven can picture humanity; the Spirit came on the 50th day (Acts 2:1), the same feast day.'),
('Leviticus', 23, 'adults', 4, 'What social justice provision was embedded within the harvest feast instructions of Leviticus 23:22?', 'Tithes must be paid to the priests before any harvest', 'Corners of the field and gleanings were to be left for the poor and the stranger', 'Harvest celebrations required a community feast', 'Farmers had to sell surplus grain at fixed prices', 'a', 'Leviticus 23:22 — "And when ye reap the harvest of your land, thou shalt not make clean riddance of the corners of thy field...thou shalt leave them unto the poor, and to the stranger."'),
('Leviticus', 23, 'adults', 5, 'What is the consequence prescribed in Leviticus 23:29-30 for not afflicting oneself on the Day of Atonement?', 'A fine of five shekels of silver', 'That soul shall be cut off from among the people and destroyed by God', 'Seven days of exclusion from the congregation', 'A doubled sin offering the following year', 'a', 'Leviticus 23:29-30 — "For whatsoever soul it be that shall not be afflicted in that same day, he shall be cut off from among his people. And whatsoever soul it be that doeth any work in that same day, the same soul will I destroy."'),
('Leviticus', 23, 'adults', 6, 'What does the Feast of Tabernacles command Israel to remember, and what is its eschatological dimension?', 'Only the wilderness wandering, with no future application', 'The wilderness sojourn and the frailty of human existence; eschatologically it points to the millennial kingdom rest when nations will celebrate (Zechariah 14:16)', 'It was purely an agricultural harvest festival', 'It foreshadowed only the return from Babylonian exile', 'a', 'Leviticus 23:43 — "That your generations may know that I made the children of Israel to dwell in booths." Zechariah 14:16 shows nations keeping this feast in the messianic age.'),
('Leviticus', 23, 'adults', 7, 'Why were two loaves of leavened bread (rather than unleavened) waved on Pentecost in Leviticus 23:17?', 'Leaven was permitted in all wave offerings', 'Scholars suggest leaven represents the sinful nature of humanity brought before God — the Church is not sinless but is accepted in Christ', 'It was simply a practical change for easier baking', 'Unleavened flour was unavailable during harvest season', 'a', 'Leviticus 23:17 — "Ye shall bring out of your habitations two wave loaves...they shall be baken with leaven; they are the firstfruits unto the LORD." The leavened loaves distinguish Pentecost from Passover offerings.'),
('Leviticus', 23, 'adults', 8, 'How does the structure of the seven feasts in Leviticus 23 form a prophetic timeline of redemptive history?', 'They are only seasonal agricultural calendars with no redemptive meaning', 'Passover, Unleavened Bread, and Firstfruits were fulfilled in Christ''s death, burial, and resurrection; Pentecost in the Spirit''s coming; Trumpets, Atonement, and Tabernacles await fulfillment at the Second Coming and kingdom', 'Only Passover has prophetic significance', 'The feasts were abolished at the cross with no future fulfillment', 'a', 'Leviticus 23 — Paul affirms the typological fulfillment: "Christ our passover is sacrificed for us" (1 Cor 5:7), "Christ the firstfruits" (1 Cor 15:23), with the fall feasts awaiting consummation.');

-- ═══ Leviticus Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 24, 'kids', 1, 'What kind of oil was used to keep the lamp burning in the tabernacle?', 'Pure olive oil', 'Sesame oil', 'Animal fat oil', 'Perfumed oil', 'a', 'Leviticus 24:2 — "Command the children of Israel, that they bring unto thee pure oil olive beaten for the light, to cause the lamps to burn continually."'),
('Leviticus', 24, 'kids', 2, 'How many loaves of bread were placed on the golden table before the LORD each week?', 'Twelve loaves', 'Seven loaves', 'Five loaves', 'Ten loaves', 'a', 'Leviticus 24:5 — "And thou shalt take fine flour, and bake twelve cakes thereof."'),
('Leviticus', 24, 'kids', 3, 'What happened to the man who cursed and blasphemed God''s name?', 'He was put out of the camp and stoned to death', 'He was fined and forgiven', 'He was put in prison', 'He was made to clean the tabernacle', 'a', 'Leviticus 24:14 — "Bring forth him that hath cursed without the camp; and let all that heard him lay their hands upon his head, and let all the congregation stone him."'),
-- Teens
('Leviticus', 24, 'teens', 1, 'How often was the bread of the presence to be set before the LORD, and who ate the old loaves?', 'Every week on the Sabbath; Aaron and his sons ate the old bread in the holy place', 'Every new moon; the Levites ate the old bread outside the camp', 'Every day; only the high priest ate it', 'Every month; it was burned as an offering', 'a', 'Leviticus 24:8-9 — "Every sabbath he shall set it in order before the LORD continually...And it shall be Aaron''s and his sons''; and they shall eat it in the holy place."'),
('Leviticus', 24, 'teens', 2, 'What was unique about the mother of the blasphemer identified in Leviticus 24?', 'She was a Canaanite woman', 'She was an Israelite woman; his father was an Egyptian', 'She was a Midianite who had converted', 'She was from the tribe of Levi', 'a', 'Leviticus 24:10-11 — "And the son of an Israelitish woman, whose father was an Egyptian, went out among the children of Israel."'),
('Leviticus', 24, 'teens', 3, 'What law concerning personal injury does Leviticus 24:19-20 establish?', 'The offender must pay double the damages', 'As he hath caused a blemish in a man, so shall it be done to him — breach for breach, eye for eye, tooth for tooth', 'The elders would determine compensation', 'The offender was banished from Israel', 'a', 'Leviticus 24:19-20 — "And if a man cause a blemish in his neighbour; as he hath done, so shall it be done to him; breach for breach, eye for eye, tooth for tooth."'),
('Leviticus', 24, 'teens', 4, 'Did the law of the blasphemer apply only to Israelites or also to strangers?', 'It applied equally to the stranger and the born Israelite alike', 'Only to native-born Israelites', 'Only to strangers since Israelites had special privilege', 'It was left to priestly discretion', 'a', 'Leviticus 24:16 — "And he that blasphemeth the name of the LORD, he shall surely be put to death, and all the congregation shall certainly stone him: as well the stranger, as he that is born in the land."'),
('Leviticus', 24, 'teens', 5, 'What frankinscense was placed with the showbread, and what happened to it?', 'Pure frankincense was laid on each row and burned as a memorial offering', 'Frankincense was mixed into the dough before baking', 'It was sprinkled on the bread and eaten with it', 'Frankincense was placed under the table', 'a', 'Leviticus 24:7 — "And thou shalt put pure frankincense upon each row, that it may be on the bread for a memorial, even an offering made by fire unto the LORD."'),
-- Adults
('Leviticus', 24, 'adults', 1, 'What is the typological significance of the seven-branched menorah burning continually before the LORD in Leviticus 24:2-4?', 'It was a practical light source for priestly work', 'It prefigures Christ as the Light of the World (John 8:12) and the Church as a lampstand bearing His light continually before God (Revelation 1:20)', 'It symbolized the seven days of creation only', 'It had no prophetic significance beyond the Levitical system', 'a', 'Leviticus 24:2 — "pure oil olive beaten for the light, to cause the lamps to burn continually." Jesus says in John 8:12, "I am the light of the world."'),
('Leviticus', 24, 'adults', 2, 'What does the phrase "before the LORD continually" applied to both the lamp and the showbread in Leviticus 24 communicate about worship?', 'Worship is only required at the major annual feasts', 'The life of the covenant community is meant to be a continuous, unbroken offering of light and provision before God — not merely periodic observance', 'It referred only to the duration of the priestly watch', 'It was a legal formula guaranteeing the priests'' income', 'a', 'Leviticus 24:3-4,8 — Both the lamp (v.3) and the bread (v.8) are to be maintained "continually" — a portrait of unceasing devotion before God''s presence.'),
('Leviticus', 24, 'adults', 3, 'How does the showbread (bread of the presence) foreshadow Christ in light of New Testament revelation?', 'It is only a priestly food regulation with no Christ-centered typology', 'The twelve loaves representing the twelve tribes set perpetually before God''s presence typify Christ as the bread of life who sustains His people in God''s presence eternally', 'It pointed to the multiplication of the loaves in John 6', 'It represented the daily manna without Christological significance', 'a', 'Leviticus 24:5-8 — Jesus declares in John 6:35, "I am the bread of life." The showbread''s perpetual presence before God typifies Christ our eternal sustainer before the Father.'),
('Leviticus', 24, 'adults', 4, 'What is the legal principle known as lex talionis established in Leviticus 24:19-21, and how does Jesus address it in the New Testament?', 'It was a harsh revenge law abolished by Moses himself', 'It established proportional justice — punishment equal to harm done; Jesus calls His disciples to a higher standard of non-retaliation in Matthew 5:38-39', 'It only applied to property disputes', 'Jesus confirmed it as still binding in all civil matters', 'a', 'Leviticus 24:20 — "eye for eye, tooth for tooth." Jesus in Matthew 5:38-39 says, "Ye have heard that it hath been said, An eye for an eye...But I say unto you, That ye resist not evil."'),
('Leviticus', 24, 'adults', 5, 'What theological principle is established by the fact that the blasphemer''s punishment applied equally to the stranger and the native Israelite in Leviticus 24:16?', 'God''s law was only a cultural covenant with ethnic Israel', 'God''s moral law is universal — His holy name demands reverence from all people regardless of ethnic or covenant status', 'Strangers were subject to stricter laws than Israelites', 'This represented a temporary measure for the wilderness period only', 'a', 'Leviticus 24:16 — "as well the stranger, as he that is born in the land, when he blasphemeth the name of the LORD, shall be put to death." God''s holiness transcends covenant membership.'),
('Leviticus', 24, 'adults', 6, 'How does the community''s act of laying their hands on the head of the blasphemer before stoning him in Leviticus 24:14 function symbolically?', 'It was a gesture of affection before punishment', 'It transferred the guilt and pollution of the blasphemy back to the offender — a ritual of communal dissociation from the sin', 'It was an act of identification with the offender''s family', 'It marked the offender for easy identification', 'a', 'Leviticus 24:14 — "let all that heard him lay their hands upon his head." This mirrors the sin-transference principle of the scapegoat (Leviticus 16:21), returning the pollution to its source.'),
('Leviticus', 24, 'adults', 7, 'What does the Hebrew phrase "the Name" (haShem) implied in Leviticus 24:11 reveal about Jewish reverence for God?', 'It is a scribal shorthand of no theological significance', 'It reflects the profound reverence for the divine name — the Name was considered so holy that even speaking it was surrounded with awe; later Jews used haShem as a substitute', 'It refers only to the Levitical title of God', 'It was a legal term for the covenant document', 'a', 'Leviticus 24:11 — "the son...blasphemed the name of the LORD." The reverence for haShem underpins why blasphemy carried the death penalty — it attacked the very identity of Israel''s God.'),
('Leviticus', 24, 'adults', 8, 'What is the structural purpose of inserting the blasphemy narrative (Leviticus 24:10-23) in the middle of priestly regulations?', 'It is a narrative interruption with no structural significance', 'It provides a concrete case study demonstrating that God''s holiness laws are not abstract — blasphemy of God''s name is the ultimate defilement, and the law is applied immediately to a real event', 'It was added later by an editor', 'It shows that narrative sections are inferior to legal codes', 'a', 'Leviticus 24:23 — "And Moses spake to the children of Israel, that they should bring forth him that had cursed out of the camp...And the children of Israel did as the LORD commanded Moses." The narrative illustrates the law in action.');

-- ═══ Leviticus Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 25, 'kids', 1, 'What was special about every seventh year for the land of Israel?', 'The land was to rest and have a Sabbath year — no planting or harvesting', 'The people had to move to a new location', 'Extra crops were planted for the poor', 'The land was given to the priests', 'a', 'Leviticus 25:4 — "But in the seventh year shall be a sabbath of rest unto the land, a sabbath for the LORD: thou shalt neither sow thy field, nor prune thy vineyard."'),
('Leviticus', 25, 'kids', 2, 'What was the Jubilee year and how often did it happen?', 'Every 50 years, when land was returned to original owners and servants were freed', 'Every 10 years, when a great feast was held', 'Every 100 years, when a new king was crowned', 'Every 7 years, when debts were forgiven', 'a', 'Leviticus 25:10 — "And ye shall hallow the fiftieth year, and proclaim liberty throughout all the land unto all the inhabitants thereof: it shall be a jubile unto you."'),
('Leviticus', 25, 'kids', 3, 'What sound announced the beginning of the Jubilee year?', 'The blowing of a trumpet on the Day of Atonement', 'The ringing of silver bells at the gate', 'A shout from the high priest', 'The beating of drums at the tabernacle', 'a', 'Leviticus 25:9 — "Then shalt thou cause the trumpet of the jubile to sound on the tenth day of the seventh month, in the day of atonement shall ye make the trumpet sound throughout all your land."'),
-- Teens
('Leviticus', 25, 'teens', 1, 'During the Sabbath year and the Jubilee, what was the Israelites'' source of food?', 'Food stored in previous years and whatever the land produced on its own', 'Food purchased from neighboring nations', 'Only bread baked from stored grain', 'They fasted for the entire year', 'a', 'Leviticus 25:6-7 — "And the sabbath of the land shall be meat for you...for thee, and for thy servant, and for thy maid...and for thy cattle, and for the beast that are in thy land, shall all the increase thereof be meat."'),
('Leviticus', 25, 'teens', 2, 'What happened to property sold in Israel at the Jubilee?', 'It returned to the family of the original owner', 'It remained with the buyer permanently', 'It became the property of the priests', 'The king distributed it equally', 'a', 'Leviticus 25:28 — "But if he be not able to restore it to him, then that which is sold shall remain in the hand of him that hath bought it until the year of jubile: and in the jubile it shall go out, and he shall return unto his possession."'),
('Leviticus', 25, 'teens', 3, 'If a poor Israelite sold himself as a servant, when was he to go free?', 'In the year of Jubilee he and his children were to be released', 'After seven years of service', 'When he had paid back double his debt', 'When the high priest declared his freedom', 'a', 'Leviticus 25:40-41 — "But as an hired servant, and as a sojourner, he shall be with thee, and shall serve thee unto the year of jubile: And then shall he depart from thee, both he and his children with him."'),
('Leviticus', 25, 'teens', 4, 'What key theological reason does God give for why the land of Israel cannot be permanently sold?', 'The land was too valuable to alienate from families', 'The land is the LORD''s — Israel were only strangers and sojourners before Him', 'The priests needed perpetual control of all land', 'Permanent sale would upset the tribal inheritance system', 'a', 'Leviticus 25:23 — "The land shall not be sold for ever: for the land is mine; for ye are strangers and sojourners with me."'),
('Leviticus', 25, 'teens', 5, 'What were Israelites forbidden to do when lending to a poor fellow Israelite?', 'Charge him interest or increase', 'Require collateral', 'Lend him more than he needed', 'Involve witnesses', 'a', 'Leviticus 25:36-37 — "Take thou no usury of him, or increase: but fear thy God; that thy brother may live with thee. Thou shalt not give him thy money upon usury, nor lend him thy victuals for increase."'),
-- Adults
('Leviticus', 25, 'adults', 1, 'What is the Jubilee''s theological foundation, and how does it reveal God''s economic theology?', 'It was a practical land redistribution policy alone', 'The Jubilee is grounded in the doctrine of divine ownership — God alone owns the land and people; all human ownership is stewardship, and the Jubilee resets human accumulation to reflect God''s sovereignty', 'It was designed to prevent population growth in Canaan', 'It was a temporary wilderness regulation that never applied in Canaan', 'a', 'Leviticus 25:23 — "The land shall not be sold for ever: for the land is mine." The Jubilee enforces the theological reality that God is ultimate owner and Israel are tenants before Him.'),
('Leviticus', 25, 'adults', 2, 'What is the messianic significance of the Jubilee proclamation of liberty in Leviticus 25:10, as applied by Jesus in Luke 4:18-19?', 'It was only a civic law with no prophetic application', 'Jesus read from Isaiah 61 — which echoes Jubilee language — and declared it fulfilled in Himself, announcing the ultimate Jubilee of spiritual liberation from sin, debt, and bondage', 'The connection between Jubilee and Isaiah 61 is coincidental', 'Jesus was only describing His preaching ministry without Jubilee typology', 'a', 'Leviticus 25:10 — "proclaim liberty throughout all the land." Jesus in Luke 4:18-19 quotes Isaiah 61:1-2 — "to proclaim the acceptable year of the Lord" — announcing Himself as the fulfillment of Jubilee.'),
('Leviticus', 25, 'adults', 3, 'How does the concept of the go''el (kinsman redeemer) in Leviticus 25:25 foreshadow Christ''s redemptive work?', 'The kinsman redeemer was only a social welfare mechanism', 'The go''el who redeems the sold inheritance of a poor kinsman typifies Christ who became our kinsman through incarnation to buy back what sin had forfeited — supremely illustrated in the book of Ruth', 'The go''el only applies to land redemption with no Christological dimension', 'Christ is only connected to the Jubilee, not the kinsman redeemer', 'a', 'Leviticus 25:25 — "If thy brother be waxen poor, and hath sold away some of his possession, and if any of his kin come to redeem it, then shall he redeem that which his brother sold." This mirrors Boaz as type of Christ in Ruth 4.'),
('Leviticus', 25, 'adults', 4, 'Why was the Sabbath year of land rest also a test of Israel''s faith, according to Leviticus 25:20-22?', 'It was a practical agricultural rotation system requiring no faith', 'Israel had to trust God explicitly when they asked "what shall we eat in the seventh year?" — God promised to command His blessing so the sixth year yielded enough for three years', 'The land rest was voluntary, so faith was uninvolved', 'God never addressed the practical concern of food supply', 'a', 'Leviticus 25:20-21 — "And if ye shall say, What shall we eat the seventh year?...Then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for three years."'),
('Leviticus', 25, 'adults', 5, 'What distinction does Leviticus 25:44-46 draw between Israelite servants and servants from surrounding nations?', 'All servants were treated identically under Mosaic law', 'Bondservants from surrounding nations could be permanent property passed to heirs, while Israelite brothers could not be treated as permanent slaves — they were to be treated as hired servants and released at Jubilee', 'The distinction was purely economic with no ethical basis', 'Israelites could not own foreign servants under any circumstances', 'a', 'Leviticus 25:44-46 — "Both thy bondmen, and thy bondmaids, which thou shalt have, shall be of the heathen...But over your brethren the children of Israel, ye shall not rule one over another with rigour."'),
('Leviticus', 25, 'adults', 6, 'What is the repeated rationale "I am the LORD your God, which brought you forth out of the land of Egypt" doing in the Jubilee laws of Leviticus 25?', 'It is a scribal insertion with no legal function', 'The exodus redemption grounds all social ethics — because God freed Israel from slavery, Israel must embody that freedom in their economic and social relations with one another', 'It only applies to the land rest regulations', 'It is a standard Deuteronomic formula with no specific connection to Jubilee', 'a', 'Leviticus 25:38,42,55 — "I am the LORD your God, which brought you forth out of the land of Egypt." The exodus is the irreducible foundation of Israel''s social ethic toward the poor and enslaved.'),
('Leviticus', 25, 'adults', 7, 'How does Leviticus 25:47-49 handle the situation where an Israelite sells himself to a wealthy sojourner?', 'He remains permanently with the sojourner', 'His relatives — brother, uncle, cousin, or any near kin — retain the right of redemption to buy him back at any time before the Jubilee', 'The congregation must approve any redemption', 'Only the high priest could authorize his release', 'a', 'Leviticus 25:48-49 — "After that he is sold he may be redeemed again; one of his brethren may redeem him: Either his uncle, or his uncle''s son, may redeem him, or any that is nigh of kin unto him."'),
('Leviticus', 25, 'adults', 8, 'What does the command "thou shalt fear thy God" inserted repeatedly into Leviticus 25''s economic laws (verses 17, 36, 43) indicate about the enforcement of these commands?', 'It shows the laws were unenforced suggestions', 'Human courts could not enforce inner motives — the fear of God was invoked as the ultimate sanction governing how the powerful treated the vulnerable when no human observer could see', 'The phrase is only a liturgical addition', 'It implies the laws applied only in formal court settings', 'a', 'Leviticus 25:17 — "Ye shall not therefore oppress one another; but thou shalt fear thy God: for I am the LORD your God." The fear of God fills the enforcement gap where human law cannot reach.');

-- ═══ Leviticus Chapter 26 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 26, 'kids', 1, 'What did God promise to give Israel if they obeyed His commandments?', 'Rain in due season, good harvests, and peace in the land', 'Gold and silver from the nations', 'A great army to defeat all enemies', 'Angels to guard their houses', 'a', 'Leviticus 26:4-6 — "Then I will give you rain in due season, and the land shall yield her increase...And I will give peace in the land."'),
('Leviticus', 26, 'kids', 2, 'What did God say would happen if Israel rejected His commandments and refused to obey?', 'He would send trouble, sickness, and enemies against them', 'He would take away their priests', 'He would give their land to other tribes', 'He would stop speaking to them', 'a', 'Leviticus 26:14-16 — "But if ye will not hearken unto me, and will not do all these commandments...I will even appoint over you terror, consumption, and the burning ague."'),
('Leviticus', 26, 'kids', 3, 'Even after all the punishment, what did God promise He would not do?', 'He would not completely destroy them or break His covenant with them', 'He would not send more plagues', 'He would not remember their sins', 'He would not let other nations see their trouble', 'a', 'Leviticus 26:44 — "And yet for all that, when they be in the land of their enemies, I will not cast them away, neither will I abhor them, to destroy them utterly, and to break my covenant with them."'),
-- Teens
('Leviticus', 26, 'teens', 1, 'What five major blessings did God promise for obedience in Leviticus 26:3-13?', 'Rain and harvests, peace, victory over enemies, fruitfulness, and God''s presence dwelling among them', 'Wealth, health, long life, knowledge, and honor', 'Land, cattle, children, gold, and silver', 'Protection, prosperity, wisdom, victory, and reputation among nations', 'a', 'Leviticus 26:4-13 covers: productive harvests (v.4-5), peace and victory (v.6-8), population fruitfulness (v.9), fulfilled covenant provision (v.10), and God''s dwelling presence (v.11-13).'),
('Leviticus', 26, 'teens', 2, 'How did God progressively intensify the punishments for continued disobedience in Leviticus 26?', 'All punishments were given at once', 'He prescribed multiple rounds of chastisement — each time Israel refused to repent He would multiply punishments seven times over', 'Punishments were randomly applied', 'Only one major punishment was described', 'a', 'Leviticus 26:18 — "And if ye will not yet for all this hearken unto me, then I will punish you seven times more for your sins." This escalation is repeated in verses 21, 24, and 28.'),
('Leviticus', 26, 'teens', 3, 'What specific agricultural curse would come upon the land during the punishment period according to Leviticus 26:19-20?', 'The land would flood continuously', 'The sky would become iron and the earth brass — no rain and no fruit from the ground', 'Locusts would eat all crops', 'All livestock would die of disease', 'a', 'Leviticus 26:19-20 — "And I will break the pride of your power; and I will make your heaven as iron, and your earth as brass: And your strength shall be spent in vain: for your land shall not yield her increase."'),
('Leviticus', 26, 'teens', 4, 'What most extreme judgment described in Leviticus 26:29 does God threaten for the worst level of Israel''s rebellion?', 'Permanent exile with no return', 'Eating the flesh of their own sons and daughters', 'The destruction of the tabernacle forever', 'The high priest being killed', 'a', 'Leviticus 26:29 — "And ye shall eat the flesh of your sons, and the flesh of your daughters shall ye eat." This was historically fulfilled during the siege of Jerusalem (2 Kings 6:28-29; Lamentations 4:10).'),
('Leviticus', 26, 'teens', 5, 'What condition did God require for the curses to cease and restoration to begin?', 'A great sacrifice at the tabernacle', 'Confession of their iniquity and of their fathers'' iniquity with humble, uncircumcised-heart repentance', 'Fifty years of exile being completed', 'The arrival of a new prophet', 'a', 'Leviticus 26:40-41 — "If they shall confess their iniquity, and the iniquity of their fathers...If then their uncircumcised hearts be humbled, and they then accept of the punishment of their iniquity."'),
-- Adults
('Leviticus', 26, 'adults', 1, 'What is the covenant structure of Leviticus 26, and how does it compare to ancient Near Eastern treaty forms?', 'It is a unique Israelite document with no parallels', 'Leviticus 26 follows the suzerainty treaty pattern — historical prologue, stipulations, blessings and curses — common in Hittite treaties, confirming Moses'' historical setting and the covenant''s formal legal character', 'It borrows from Egyptian administrative law', 'The blessings-and-curses form was invented by Ezra', 'a', 'Leviticus 26 follows the standard ANE vassal treaty form. Deuteronomy 28 mirrors the same structure, and scholars note the parallel to Hittite treaties from the 15th-13th centuries BC.'),
('Leviticus', 26, 'adults', 2, 'What does the promise "I will walk among you, and will be your God, and ye shall be my people" in Leviticus 26:12 theologically anticipate?', 'Only the wilderness tabernacle arrangement', 'The covenant formula fulfilled progressively: in the tabernacle, in Christ (John 1:14), in the Church (2 Cor 6:16), and ultimately in the New Jerusalem (Rev 21:3)', 'Only the future kingdom of Solomon', 'A temporary arrangement abolished at the exile', 'a', 'Leviticus 26:12 — "I will walk among you, and will be your God, and ye shall be my people." This formula recurs in 2 Corinthians 6:16 and Revelation 21:3 as the consummation of all covenant promises.'),
('Leviticus', 26, 'adults', 3, 'How many cycles of sevenfold intensification are threatened in Leviticus 26, and what does the number seven signify in this context?', 'Two cycles; seven is only a round number', 'Four cycles of sevenfold punishment; seven represents complete divine judgment — God will bring full covenantal justice until Israel''s repentance', 'Three cycles; seven refers to the seven feasts', 'Five cycles; seven reflects the five books of Moses', 'a', 'Leviticus 26:18,21,24,28 — "I will punish you seven times more" appears four times. Seven connotes completeness and covenant fullness in Hebrew thought — God''s discipline is thorough and purposeful.'),
('Leviticus', 26, 'adults', 4, 'What is the significance of the "high places" (bamoth) being destroyed in the curse section of Leviticus 26:30?', 'They were only military fortifications', 'The bamoth were syncretistic worship sites that symbolized Israel''s idolatry — their destruction in judgment mirrors the very sin they enabled; God judges by removing the instrument of rebellion', 'They were grain storage structures', 'They were legitimate worship sites condemned only for their location', 'a', 'Leviticus 26:30 — "And I will destroy your high places, and cut down your images." The bamoth became a persistent spiritual cancer in Israel''s history (1 Kings 12:31; 2 Kings 17:9), ultimately precipitating the exile.'),
('Leviticus', 26, 'adults', 5, 'What does "the land shall enjoy her sabbaths" in Leviticus 26:34-35 reveal about the exile and the Sabbath year law?', 'It is a metaphorical expression with no historical reference', 'The land desolation during exile would accomplish the Sabbath rests Israel had withheld — 2 Chronicles 36:21 explicitly connects 70 years of Babylonian exile to the violated Sabbath years', 'The land Sabbath only applied after the conquest', 'The verse is a later addition explaining the exile', 'a', 'Leviticus 26:34-35 fulfilled in 2 Chronicles 36:21 — "To fulfil the word of the LORD by the mouth of Jeremiah, until the land had enjoyed her sabbaths: for as long as she lay desolate she kept sabbath."'),
('Leviticus', 26, 'adults', 6, 'What is the theological significance of God remembering the covenant with Abraham, Isaac, and Jacob in Leviticus 26:42 as the ground of Israel''s restoration?', 'It shows the patriarchal covenant was conditional on Israel''s perfect obedience', 'Restoration is grounded in the unconditional Abrahamic covenant — not in Israel''s merit — demonstrating that God''s faithfulness to His sworn oath ultimately overrides the covenant curses', 'The verse shows three separate covenants being merged', 'It suggests God forgot the covenant temporarily', 'a', 'Leviticus 26:42 — "Then will I remember my covenant with Jacob...with Isaac...with Abraham will I remember." The patriarchal covenant is the unbreakable foundation beneath all covenant discipline (Romans 11:28-29).'),
('Leviticus', 26, 'adults', 7, 'What does Leviticus 26:41 mean by "their uncircumcised hearts be humbled"?', 'Physical circumcision must be repeated', 'The problem Israel faced was never merely physical non-circumcision but heart-hardness — true repentance requires the inner covenant sign, a theme developed in Deuteronomy 30:6, Jeremiah 4:4, and Romans 2:29', 'Only the Gentiles needed heart circumcision', 'It refers to the ritual impurity of uncircumcised foreigners in the camp', 'a', 'Leviticus 26:41 — "their uncircumcised hearts be humbled." Deuteronomy 30:6 — "The LORD thy God will circumcise thine heart." Fulfilled spiritually in Romans 2:29 and Colossians 2:11.'),
('Leviticus', 26, 'adults', 8, 'How does the structure of blessings and curses in Leviticus 26 reflect the character of God as both holy judge and covenant-keeping redeemer?', 'It presents God as primarily a wrathful deity with mercy as an afterthought', 'The chapter reveals that God''s discipline serves a redemptive purpose — the curses are not ultimate rejection but covenant correction designed to bring Israel to confession; the chapter ends with mercy (v.44-45), showing wrath in service of love', 'The curses demonstrate God''s permanent abandonment of disobedient Israel', 'Mercy is only mentioned as a possibility, not a certainty', 'a', 'Leviticus 26:44 — "I will not cast them away, neither will I abhor them...to break my covenant with them: for I am the LORD their God." Holy wrath and covenant mercy are both essential to God''s character.');

-- ═══ Leviticus Chapter 27 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Leviticus', 27, 'kids', 1, 'What does it mean to make a special vow to God in Leviticus 27?', 'To promise a person, animal, house, or field to the LORD with a set value', 'To fast for seven days', 'To bring extra bread to the tabernacle', 'To build a new altar', 'a', 'Leviticus 27:2 — "When a man shall make a singular vow, the persons shall be for the LORD by thy estimation."'),
('Leviticus', 27, 'kids', 2, 'Could a vowed item that was "most holy" be sold or redeemed?', 'No, it could not be redeemed — it was most holy unto the LORD', 'Yes, for double its value', 'Only the high priest could redeem it', 'Yes, on the Day of Atonement', 'a', 'Leviticus 27:28 — "Notwithstanding no devoted thing, that a man shall devote unto the LORD of all that he hath...shall be sold or redeemed: every devoted thing is most holy unto the LORD."'),
('Leviticus', 27, 'kids', 3, 'What was the tithe — how much did Israelites give to God from their flocks and herds?', 'One tenth of everything that passed under the rod', 'One half of everything', 'One quarter of every harvest', 'One animal from each tribe per year', 'a', 'Leviticus 27:32 — "And concerning the tithe of the herd, or of the flock, even of whatsoever passeth under the rod, the tenth shall be holy unto the LORD."'),
-- Teens
('Leviticus', 27, 'teens', 1, 'What was the valuation of a male between 20 and 60 years old if dedicated to the LORD?', 'Fifty shekels of silver', 'Thirty shekels of silver', 'Twenty shekels of silver', 'Ten shekels of silver', 'a', 'Leviticus 27:3 — "then thy estimation shall be of the male from twenty years old even unto sixty years old, even thy estimation shall be fifty shekels of silver."'),
('Leviticus', 27, 'teens', 2, 'What provision was made for a person who was too poor to pay the full valuation of their vow?', 'The vow was cancelled without penalty', 'The priest would set a value according to what the person could afford', 'They would serve at the tabernacle instead', 'They would pay over multiple years', 'a', 'Leviticus 27:8 — "But if he be poorer than thy estimation, then he shall present himself before the priest, and the priest shall value him; according to his ability that vowed shall the priest value him."'),
('Leviticus', 27, 'teens', 3, 'What happened if someone wanted to redeem a clean animal that had been vowed to the LORD?', 'It was allowed freely at any time', 'He must add a fifth part to its valuation and pay that to redeem it', 'He had to bring a replacement animal first', 'He had to wait until the next Jubilee', 'a', 'Leviticus 27:13 — "But if he will at all redeem it, then he shall add a fifth part thereof unto thy estimation."'),
('Leviticus', 27, 'teens', 4, 'Could the firstborn of an animal be dedicated as a vow to the LORD?', 'No, because firstborns already belonged to the LORD', 'Yes, firstborns could be vowed like any other animal', 'Only if the animal was a sheep or goat', 'Only the firstborn of unclean animals', 'a', 'Leviticus 27:26 — "Only the firstling of the beasts, which should be the LORD''s firstling, no man shall sanctify it; whether it be ox, or sheep: it is the LORD''S."'),
('Leviticus', 27, 'teens', 5, 'If a man dedicated a field of his possession to the LORD, what determined its valuation?', 'The number of years remaining until the Jubilee and the measure of seed needed to sow it', 'Its location relative to the tabernacle', 'The quality of its soil judged by the elders', 'The previous year''s harvest yield', 'a', 'Leviticus 27:16 — "And if a man shall sanctify unto the LORD some part of a field of his possession, then thy estimation shall be according to the seed thereof: an homer of barley seed shall be valued at fifty shekels of silver."'),
-- Adults
('Leviticus', 27, 'adults', 1, 'What is the theological purpose of the valuations system in Leviticus 27, and what does it reveal about vow-making in Israel?', 'It was purely a financial regulatory system', 'The valuations created a structured pathway for fulfilling vows — ensuring that sincere devotion to God could be honored even when the vowed object could not literally serve at the sanctuary; it prevented rash vows from becoming unresolvable burdens', 'It was a priestly income mechanism disguised as piety', 'It allowed wealthy Israelites to avoid actual service to God', 'a', 'Leviticus 27:2-8 — The valuation system allows dedication of persons by monetary equivalent, harmonizing sincere vow-making with practical reality while honoring God''s claim on what was promised.'),
('Leviticus', 27, 'adults', 2, 'What is the significance of the fifth-part addition required when redeeming vowed items in Leviticus 27?', 'It was arbitrary taxation by priests', 'The 20% surcharge acknowledged that switching from the vowed object to a monetary substitute was a concession — God''s claim was primary, and the extra fifth honored that priority while allowing practical flexibility', 'It was a deterrent to discourage all vow-making', 'It only applied to unclean animals', 'a', 'Leviticus 27:13,15,19,27,31 — The fifth-part surcharge appears repeatedly in redemption laws, indicating the seriousness of a vow and the privilege — not the right — of redemption.'),
('Leviticus', 27, 'adults', 3, 'How does the irredeemability of cherem (devoted things) in Leviticus 27:28-29 relate to the concept of holy war in the book of Joshua?', 'Cherem was only an economic regulation with no military application', 'Things placed under cherem were absolutely God''s — this principle drove the holy war bans in Canaan (Joshua 6:17-21) where the spoil belonged to God; violation by Achan in Joshua 7 brought judgment on all Israel', 'Joshua''s wars had no connection to Levitical law', 'Cherem only applied to animals and property, not to military conquest', 'a', 'Leviticus 27:28 — "every devoted thing is most holy unto the LORD." Joshua 6:17 — "the city shall be accursed (cherem)...unto the LORD." Achan''s theft of cherem (Joshua 7:1) violated this principle directly.'),
('Leviticus', 27, 'adults', 4, 'What does Leviticus 27:29 — "None devoted, which shall be devoted of men, shall be redeemed; but shall surely be put to death" — indicate about the most severe form of cherem?', 'It refers to persons who stumbled into the sanctuary', 'Persons placed under full cherem — whether enemy combatants in holy war or those guilty of capital covenant violation — were absolutely given over to divine judgment with no ransom substitute possible', 'It applied only to criminals convicted three times', 'It was a theoretical provision never actually enforced', 'a', 'Leviticus 27:29 — "None devoted...shall be redeemed; but shall surely be put to death." This creates the theological category of irreversible divine judgment, echoed in Hebrews 10:26-29 regarding willful post-enlightenment apostasy.'),
('Leviticus', 27, 'adults', 5, 'What does the tithe law in Leviticus 27:30-33 establish as the primary character of the tithe?', 'The tithe is a voluntary gift expressing generosity', 'The tithe is holy to the LORD — it is His by right, not a gift from the worshipper; Israel renders to God what already belongs to Him', 'The tithe was only for agricultural produce', 'The tithe replaced all other offerings', 'a', 'Leviticus 27:30 — "And all the tithe of the land, whether of the seed of the land, or of the fruit of the tree, is the LORD''S: it is holy unto the LORD." The tithe acknowledges God''s prior ownership of all increase.'),
('Leviticus', 27, 'adults', 6, 'Why was a person forbidden to exchange a tithed animal for another — and what additional consequence applied if they tried?', 'God had no preference regarding which specific animal was tithed', 'Exchanging the tithe animal showed attempted manipulation of God''s portion; if exchange was made, both the original and the substitute became holy and could not be redeemed', 'Exchange was forbidden only for firstlings', 'Only the high priest could authorize any substitution', 'a', 'Leviticus 27:33 — "He shall not search whether it be good or bad, neither shall he change it: and if he change it at all, then both it and the change thereof shall be holy; it shall not be redeemed."'),
('Leviticus', 27, 'adults', 7, 'How does the gender and age-based valuation table in Leviticus 27:3-7 function as a practical system rather than an inherent statement of human worth?', 'It establishes a theological hierarchy of human value by gender and age', 'The valuations reflect economic labor productivity at each life stage — they are functional equivalents for temple service contribution, not statements of intrinsic dignity before God; all persons made in God''s image have equal worth', 'The table was later revised to equalize male and female valuations', 'It shows women had no role in the covenant community', 'a', 'Leviticus 27:3-7 sets tiered valuations by age and sex based on productive capacity. This is a pragmatic service-equivalent system, not a dignity ranking — all humans bear the image of God (Genesis 1:27).'),
('Leviticus', 27, 'adults', 8, 'What is the literary and theological significance of Leviticus ending with chapter 27 on vows and dedications rather than with the covenant curses of chapter 26?', 'It is an editorial accident — chapter 27 is an appendix with no structural purpose', 'Ending with voluntary dedication laws shows that the appropriate response to all God has commanded in Leviticus is wholehearted, willing self-offering — God desires not merely legal compliance but joyful consecration of persons, property, and possessions to His service', 'Chapter 27 was added by a later scribe who misunderstood the structure', 'It shows the legal code takes priority over covenant relationship', 'a', 'Leviticus 27:2 — "When a man shall make a singular vow." After all the commands, blessings, and curses, Leviticus ends with a vision of Israel freely vowing themselves and their goods to God — the goal of all the law is a people devoted to the LORD.');
